          //ang2 *= 0.95;
        #endif

    ang2 *= 0.95;

    ang2 += uTime*0.05;
    float fin_sin = sin(ang2)*1;
    float fin_cos = cos(ang2)*1;
    vUv = 0.5 + rad2*vec2(fin_cos, fin_sin)*uTexSize.zw;

    ret = mix(GetPixel(vUv).y*pow(hue_shader,4)*4,GetPixel(vUv).x,pow(hue_shader,2)*2);
